-/// Tokenizer state
-pub const Tokenizer = struct {
-    const Self = @This();
-
-    allocator: Allocator,
-    source: []const u8,
-    pos: usize = 0,
-    line: u32 = 1,
-    col: u32 = 0,
-    /// Indentation stack
-    indent_stack: std.ArrayList(u32),
-    /// Pending dedents to emit
-    pending_dedents: u32 = 0,
-    /// Bracket nesting level
-    bracket_level: u32 = 0,
-    /// At beginning of line
-    at_bol: bool = true,
-    /// In f-string
-    in_fstring: bool = false,
-    /// Error message if any
-    error_msg: ?[]const u8 = null,
-
-    pub fn init(allocator: Allocator, source: []const u8) Self {
-        var self = Self{
-            .allocator = allocator,
-            .source = source,
-            .indent_stack = std.ArrayList(u32).init(allocator),
-        };
-        // Start with 0 indentation
-        self.indent_stack.append(0) catch {};
-        return self;
-    }
-
-    pub fn deinit(self: *Self) void {
-        self.indent_stack.deinit();
-    }
-
-    /// Get next token
-    pub fn nextToken(self: *Self) !Token {
-        // Emit pending dedents
-        if (self.pending_dedents > 0) {
-            self.pending_dedents -= 1;
-            return Token{
-                .type_ = .DEDENT,
-                .start = self.currentPos(),
-                .end = self.currentPos(),
-                .string = "",
-            };
-        }
-
-        // Skip whitespace and handle indentation at BOL
-        if (self.at_bol and self.bracket_level == 0) {
-            try self.handleIndentation();
-            if (self.pending_dedents > 0) {
-                self.pending_dedents -= 1;
-                return Token{
-                    .type_ = .DEDENT,
-                    .start = self.currentPos(),
-                    .end = self.currentPos(),
-                    .string = "",
-                };
-            }
-        }
-
-        // Skip spaces (not at BOL)
-        while (self.pos < self.source.len and (self.source[self.pos] == ' ' or self.source[self.pos] == '\t')) {
-            self.advance();
-        }
-
-        // End of input
-        if (self.pos >= self.source.len) {
-            // Emit final dedents
-            if (self.indent_stack.items.len > 1) {
-                _ = self.indent_stack.pop();
-                self.pending_dedents = @intCast(self.indent_stack.items.len - 1);
-                if (self.pending_dedents > 0) {
-                    self.pending_dedents -= 1;
-                    return Token{
-                        .type_ = .DEDENT,
-                        .start = self.currentPos(),
-                        .end = self.currentPos(),
-                        .string = "",
-                    };
-                }
-            }
-            return Token{
-                .type_ = .ENDMARKER,
-                .start = self.currentPos(),
-                .end = self.currentPos(),
-                .string = "",
-            };
-        }
-
-        const start = self.currentPos();
-        const c = self.source[self.pos];
-
-        // Comment
-        if (c == '#') {
-            const comment_start = self.pos;
-            while (self.pos < self.source.len and self.source[self.pos] != '\n') {
-                self.advance();
-            }
-            return Token{
-                .type_ = .COMMENT,
-                .start = start,
-                .end = self.currentPos(),
-                .string = self.source[comment_start..self.pos],
-            };
-        }
-
-        // Newline
-        if (c == '\n') {
-            self.advance();
-            self.at_bol = true;
-            if (self.bracket_level > 0) {
-                return Token{
-                    .type_ = .NL,
-                    .start = start,
-                    .end = self.currentPos(),
-                    .string = "\n",
-                };
-            }
-            return Token{
-                .type_ = .NEWLINE,
-                .start = start,
-                .end = self.currentPos(),
-                .string = "\n",
-            };
-        }
-
-        self.at_bol = false;
-
-        // String
-        if (c == '"' or c == '\'') {
