+        if (std.mem.eql(u8, name, "await")) {
+            return Token{ .type_ = .AWAIT, .start = start, .end = self.currentPos(), .string = name };
+        }
+
+        return Token{
+            .type_ = .NAME,
+            .start = start,
+            .end = self.currentPos(),
+            .string = name,
+        };
+    }
