+                    .Add => .Add,
+                    .Sub => .Sub,
+                    .Mult => .Mult,
+                    .Div => .Div,
+                    .FloorDiv => .FloorDiv,
+                    .Mod => .Mod,
+                    .Pow => .Pow,
+                };
+                try self.instructions.append(self.allocator, .{ .op = op });
+            },
+
+            else => return error.UnsupportedASTNode, // Node type not yet supported in bytecode compiler
+        }
+    }
+};

