+    fn buildTuple(self: *Self, args: *ArgIterator) BuildError!BuiltValue {
+        self.advance(); // skip '('
+        const count = try self.countFormat(')');
+
+        var items: std.ArrayList(BuiltValue) = .{};
+        errdefer items.deinit(self.allocator);
